import{_ as a,c as e,o as n,a5 as l}from"./chunks/framework.DwbewbAn.js";const m=JSON.parse('{"title":"Go面试题","description":"","frontmatter":{},"headers":[],"relativePath":"doc/编程语言/后端/Go/实战/Go面试问题.md","filePath":"packages/doc/src/编程语言/后端/Go/实战/Go面试问题.md","lastUpdated":1711551906000}'),o={name:"doc/编程语言/后端/Go/实战/Go面试问题.md"},t=l(`<h1 id="go面试题" tabindex="-1">Go面试题 <a class="header-anchor" href="#go面试题" aria-label="Permalink to &quot;Go面试题&quot;">​</a></h1><h2 id="_1-逃逸分析" tabindex="-1">1.逃逸分析 <a class="header-anchor" href="#_1-逃逸分析" aria-label="Permalink to &quot;1.逃逸分析&quot;">​</a></h2><h4 id="什么是内存逃逸" tabindex="-1">什么是内存逃逸？ <a class="header-anchor" href="#什么是内存逃逸" aria-label="Permalink to &quot;什么是内存逃逸？&quot;">​</a></h4><p><code>golang程序变量</code>会携带有一组校验数据，用来证明它的整个生命周期是否在运行时完全可知。如果变量通过了这些校验，它就可以在<code>栈上</code>分配。否则就说它 <code>逃逸</code> 了，必须在<code>堆上分配</code>。</p><p>能引起变量逃逸到堆上的<strong>典型情况</strong>：</p><ul><li><strong>在方法内把局部变量指针返回</strong> 局部变量原本应该在栈中分配，在栈中回收。但是由于返回时被外部引用，因此其生命周期大于栈，则溢出。</li><li><strong>发送指针或带有指针的值到 channel 中。</strong> 在编译时，是没有办法知道哪个 goroutine 会在 channel 上接收数据。所以编译器没法知道变量什么时候才会被释放。</li><li><strong>在一个切片上存储指针或带指针的值。</strong> 一个典型的例子就是 []*string 。这会导致切片的内容逃逸。尽管其后面的数组可能是在栈上分配的，但其引用的值一定是在堆上。</li><li><strong>slice 的背后数组被重新分配了，因为 append 时可能会超出其容量( cap )。</strong> slice 初始化的地方在编译时是可以知道的，它最开始会在栈上分配。如果切片背后的存储要基于运行时的数据进行扩充，就会在堆上分配。</li><li><strong>在 interface 类型上调用方法。</strong> 在 interface 类型上调用方法都是动态调度的 —— 方法的真正实现只能在运行时知道。想像一个 io.Reader 类型的变量 r , 调用 r.Read(b) 会使得 r 的值和切片b 的背后存储都逃逸掉，所以会在堆上分配。</li></ul><p>通过 <code>go build -gcflags=-m</code> 查看逃逸的情况</p><h3 id="如何避免逃逸" tabindex="-1">如何避免逃逸？ <a class="header-anchor" href="#如何避免逃逸" aria-label="Permalink to &quot;如何避免逃逸？&quot;">​</a></h3><p>在<code>runtime/stubs.go 有个函数叫</code>noescape<code>。</code>noescape\`可以在逃逸分析中<strong>隐藏一个指针</strong>。让这个指针在逃逸分析中<strong>不会被检测为逃逸</strong>。</p><h2 id="_2-map实现原理" tabindex="-1">2.Map实现原理 <a class="header-anchor" href="#_2-map实现原理" aria-label="Permalink to &quot;2.Map实现原理&quot;">​</a></h2><p><a href="https://blog.csdn.net/xiaodaoge_it/article/details/121297144" target="_blank" rel="noreferrer">https://blog.csdn.net/xiaodaoge_it/article/details/121297144</a></p><p>1.key不能重复，底层使用hash表</p><p>2.在go的map实现中，它的底层结构体是hmap，hmap里维护着若干个bucket数组 (即桶数组)。</p><p>Bucket数组中每个元素都是bmap结构，也即每个bucket（桶）都是bmap结构，【ps：后文为了语义一致，和方便理解，就不再提bmap了，统一叫作桶】 每个桶中保存了8个kv对，如果8个满了，又来了一个key落在了这个桶里，会使用overflow连接下一个桶(溢出桶)。</p><h2 id="_3-mutex实现原理" tabindex="-1">3.Mutex实现原理 <a class="header-anchor" href="#_3-mutex实现原理" aria-label="Permalink to &quot;3.Mutex实现原理&quot;">​</a></h2><p><a href="https://zhuanlan.zhihu.com/p/360491560" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/360491560</a></p><p>保护临界资源</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>type Mutex struct {</span></span>
<span class="line"><span>	state int32</span></span>
<span class="line"><span>	sema  uint32</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>非常简单，就两个成员：</p><ol><li>state</li><li>sema</li></ol><p>其中，state采用不同位表示不同含义的方式进行定义的，按从低到高位一次排列：</p><ol><li>第一位表示加锁状态：0表示未加锁，1表示已加锁</li><li>第二位表示唤醒状态：0表示未设置被唤醒状态，1表示已设置被唤醒状态</li><li>第三位表示运行状态：0表示正常状态，1表示饥饿状态</li><li>第四位以及其他字节位：表示等待获取锁的数目</li></ol><p>另外的sema为信号量，通过其P/V操作实现锁的等待和唤醒</p><h2 id="加锁逻辑" tabindex="-1"><strong>加锁逻辑</strong> <a class="header-anchor" href="#加锁逻辑" aria-label="Permalink to &quot;**加锁逻辑**&quot;">​</a></h2><ol><li><strong>快速加锁</strong></li></ol><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>if atomic.CompareAndSwapInt32(&amp;m.state, 0, mutexLocked) {</span></span>
<span class="line"><span>       return</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>采用CAS实现快速加锁</p><p><strong>2. 缓慢加锁（slowLock）</strong></p><p>为了充分提高加锁效率，golang的mutex的运行状态有两种：正常状态和饥饿状态</p><p>正常状态下：刚进入锁的协程可通过自旋锁的方式快速获取锁；</p><p>饥饿模式下：所有锁的获取者都通过FIFO的方式公平的获取锁资源</p><ul><li>自旋锁</li></ul><p>从操作系统的角度来看，相比睡眠方式的互斥锁，自旋锁通过自旋占用CPU，避免的CPU的上下文切换，因此在持锁时长较短的情况下，性能更优</p><p>golang的mutex在实现时，充分考虑了自旋锁跟睡眠锁的取舍；即：在持锁时长较短时，采用自旋锁，在持锁时长较大时，采用睡眠锁</p><p>非饥饿状态下，自旋后获取新的state锁信息，如果发现锁状态为未加锁状态，则使用CAS获取锁</p><p>源码解析，在以下情况下不可进入自旋：</p><ol><li>迭代次数(入参i) 大于等于4</li><li>cpu为单核</li><li>GOMAXPROCS大于1且至少有一个其他处理运行状态的P</li><li>当前P没有其他等待运行的G</li></ol><p>深入分析，procyield底层采用了循环条用PAUSE和JNZ指令</p><p><strong>饥饿状态</strong></p><p>正常模式下，由于刚进入锁的协程有较高的获取锁优势，所以可能会出现某个进程一直获取不到锁的情况发生，golang的Mutex为了避免这种情况，引入了饥饿状态</p><p>在某个协程超过1ms依旧没有获取到锁的情况下，mutex进入饥饿模式；进入饥饿模式后，刚进入锁的协程不进行自旋，直接放入到sema信号量的队尾，并将锁的等待着加1；</p><h2 id="解锁逻辑" tabindex="-1">解锁逻辑 <a class="header-anchor" href="#解锁逻辑" aria-label="Permalink to &quot;解锁逻辑&quot;">​</a></h2><p>相对加锁逻辑，解锁逻辑相对简单；</p><ol><li><strong>快速解锁</strong></li></ol><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>func (m *Mutex) Unlock() {</span></span>
<span class="line"><span>	new := atomic.AddInt32(&amp;m.state, -mutexLocked)</span></span>
<span class="line"><span>	if new != 0 {</span></span>
<span class="line"><span>		m.unlockSlow(new)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>解锁后，锁状态恢复到初始状态（即没有其他获取锁的协程）</p><p><strong>2. 缓慢解锁（slowUnlock）</strong></p><p><strong>异常处理</strong></p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>if (new+mutexLocked)&amp;mutexLocked == 0 {</span></span>
<span class="line"><span>	throw(&quot;sync: unlock of unlocked mutex&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>针对未加锁的情况下调用解锁逻辑，直接抛出异常</p><p><strong>饥饿模式</strong></p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>if new&amp;mutexStarving == 0 {</span></span>
<span class="line"><span>} else {</span></span>
<span class="line"><span>	runtime_Semrelease(&amp;m.sema, true, 1)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>饥饿模式下，直接调用runtime_Semrelease唤醒对头协程</p><p>正常模式下，如果锁的等待者为0或者锁已经被其他进入锁的协程获取了，则不唤醒等待协程</p><h2 id="锁特性总结" tabindex="-1">锁特性总结 <a class="header-anchor" href="#锁特性总结" aria-label="Permalink to &quot;锁特性总结&quot;">​</a></h2><ol><li>总体上，golang的互斥锁实现为一公平锁，不会出现某进程被“饿死”的情况；但正常模式下，被唤醒的协程需要与当前进入锁的协程竞争锁，但通常情况下，当前进入锁的协程拥有更好的获取锁的优势</li><li>非并发场景下，mutex通过CAS实现快速加锁、解锁</li><li>正常模式下，通过自旋实现快速获取锁</li><li>饥饿模式下，采用FIFO方式获取锁</li><li>加锁解锁不限制于相同的协程中</li></ol><h2 id="_4-context原理" tabindex="-1">4.Context原理 <a class="header-anchor" href="#_4-context原理" aria-label="Permalink to &quot;4.Context原理&quot;">​</a></h2><p><a href="https://zhuanlan.zhihu.com/p/110085652" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/110085652</a></p><p>目的：并发编程中用来传递上下文，可以做取消动作</p><h3 id="context接口" tabindex="-1">Context接口 <a class="header-anchor" href="#context接口" aria-label="Permalink to &quot;Context接口&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>type Context interface {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Deadline() (deadline time.Time, ok bool)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Done() &lt;-chan struct{}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Err() error</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Value(key interface{}) interface{}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="emptyctx" tabindex="-1">emptyCtx <a class="header-anchor" href="#emptyctx" aria-label="Permalink to &quot;emptyCtx&quot;">​</a></h3><p><code>emptyCtx</code>是一个<code>int</code>类型的变量，但实现了<code>context</code>的接口。<code>emptyCtx</code>没有超时时间，不能取消，也不能存储任何额外信息，所以<code>emptyCtx</code>用来作为<code>context</code>树的根节点。</p><p>2种实现</p><p><code>Background</code>和<code>TODO</code>只是用于不同场景下： <code>Background</code>通常被用于主函数、初始化以及测试中，作为一个顶层的<code>context</code>，也就是说一般我们创建的<code>context</code>都是基于<code>Background</code>；而<code>TODO</code>是在不确定使用什么<code>context</code>的时候才会使用。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>valueCtx\`和\`cancelCtx</span></span>
<span class="line"><span>valueCtx利用一个Context类型的变量来表示父节点context，所以当前context继承了父context的所有信息；valueCtx类型还携带一组键值对，也就是说这种context可以携带额外的信息。valueCtx实现了Value方法，用以在context链路上获取key对应的值，如果当前context上不存在需要的key,会沿着context链向上寻找key对应的值，直到根节点。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="cancelctx" tabindex="-1">cancelCtx <a class="header-anchor" href="#cancelctx" aria-label="Permalink to &quot;cancelCtx&quot;">​</a></h3><h3 id="withcancel" tabindex="-1">WithCancel <a class="header-anchor" href="#withcancel" aria-label="Permalink to &quot;WithCancel&quot;">​</a></h3><h3 id="timerctx" tabindex="-1">timerCtx <a class="header-anchor" href="#timerctx" aria-label="Permalink to &quot;timerCtx&quot;">​</a></h3><h3 id="withdeadline" tabindex="-1">WithDeadline <a class="header-anchor" href="#withdeadline" aria-label="Permalink to &quot;WithDeadline&quot;">​</a></h3><h3 id="withtimeout" tabindex="-1">WithTimeout <a class="header-anchor" href="#withtimeout" aria-label="Permalink to &quot;WithTimeout&quot;">​</a></h3><p><code>context</code>主要用于父子任务之间的同步取消信号，本质上是一种协程调度的方式。另外在使用<code>context</code>时有两点值得注意：上游任务仅仅使用<code>context</code>通知下游任务不再需要，但不会直接干涉和中断下游任务的执行，由下游任务自行决定后续的处理操作，也就是说<code>context</code>的取消操作是无侵入的；<code>context</code>是线程安全的，因为<code>context</code>本身是不可变的（<code>immutable</code>），因此可以放心地在多个协程中传递使用。</p><h2 id="_5-gmp调度原理" tabindex="-1">5.GMP调度原理 <a class="header-anchor" href="#_5-gmp调度原理" aria-label="Permalink to &quot;5.GMP调度原理&quot;">​</a></h2><p><a href="https://www.cnblogs.com/failymao/p/15318527.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/failymao/p/15318527.html</a></p><p>G---goroutine协程</p><p>P---processor处理器</p><p>M---线程</p><ul><li>全局队列（Global Queue）：存放等待运行的 G。</li><li>P为本地队列：同全局队列类似，存放的也是等待运行的 Goroutine，存的数量有限，不超过 256 个。新建 <code>G</code>时，<code>G</code>优先加入到 P 的本地队列，如果队列满了，则会把本地队列中一半的 G 移动到全局队列。</li><li>P 列表：所有的 P 都在程序启动时创建，并保存在数组中，最多有 GOMAXPROCS(可配置) 个。</li><li>M：线程想运行任务就得获取 P，从 P 的本地队列获取 G，P 队列为空时，M 也会尝试从全局队列拿一批 G 放到 P 的本地队列，或从其他 P 的本地队列偷一半放到自己 P 的本地队列。M 运行 G，G 执行之后，M 会从 P 获取下一个 G，不断重复下去。</li></ul><p>Goroutine 调度器和 OS 调度器是通过 M 结合起来的，每个 M 都代表了 1 个内核线程，OS 调度器负责把内核线程分配到 CPU 的核上执行。</p><h3 id="有关m和p的个数问题" tabindex="-1">有关M和P的个数问题 <a class="header-anchor" href="#有关m和p的个数问题" aria-label="Permalink to &quot;有关M和P的个数问题&quot;">​</a></h3><ol><li>P的数量： <ul><li>由启动时环境变量 $GOMAXPROCS 或者是由 runtime 的方法 GOMAXPROCS() 决定。这意味着在程序执行的任意时刻都只有 $GOMAXPROCS 个 goroutine 在同时运行。</li></ul></li><li>M的数量： <ul><li>go 语言本身的限制：go 程序启动时，会设置 M 的最大数量，默认 10000. 但是内核很难支持这么多的线程数，所以这个限制可以忽略。</li><li>runtime/debug 中的 SetMaxThreads 函数，设置 M 的最大数量</li><li>一个 M 阻塞了，会创建新的 M。</li></ul></li></ol><p>M 与 P 的数量没有绝对关系，一个 M 阻塞，P 就会去创建或者切换另一个 M，所以，即使 P 的默认数量是 1，也有可能会创建很多个 M 出来。</p><h3 id="p-和-m-何时会被创建" tabindex="-1">P 和 M 何时会被创建 <a class="header-anchor" href="#p-和-m-何时会被创建" aria-label="Permalink to &quot;P 和 M 何时会被创建&quot;">​</a></h3><ol><li>在确定了 P 的最大数量 n 后，运行时系统会根据这个数量创建 n 个 P。</li><li>没有足够的 M 来关联 P 并运行其中的可运行的 G。比如所有的 M 此时都阻塞住了，而 P 中还有很多就绪任务，就会去寻找空闲的 M，而没有空闲的，就会去创建新的 M。</li></ol><h2 id="调度器的设计策略" tabindex="-1">调度器的设计策略 <a class="header-anchor" href="#调度器的设计策略" aria-label="Permalink to &quot;调度器的设计策略&quot;">​</a></h2><p>复用线程：避免频繁的创建、销毁线程，而是对线程的复用。</p><ol><li>work stealing 机制 <ul><li>当本线程无可运行的 G 时，尝试从其他线程绑定的 P 偷取 G，而不是销毁线程。</li></ul></li><li>hand off 机制 <ul><li>当本线程因为 G 进行系统调用阻塞时，线程释放绑定的 P，把 P 转移给其他空闲的线程执行。</li></ul></li></ol><p><strong>利用并行</strong>：GOMAXPROCS 设置 P 的数量，最多有 GOMAXPROCS 个线程分布在多个 CPU 上同时运行。GOMAXPROCS 也限制了并发的程度，比如 GOMAXPROCS = 核数/2，则最多利用了一半的 CPU 核进行并行。</p><p><strong>抢占</strong>：在 coroutine 中要等待一个协程主动让出 CPU 才执行下一个协程，在 Go 中，一个 goroutine 最多占用 CPU 10ms，防止其他 goroutine 被饿死，这就是 goroutine 不同于 coroutine 的一个地方。</p><p><strong>全局 G 队列</strong>：，当 M 执行 work stealing 从其他 P 偷不到 G 时，它可以从全局 G 队列获取 G</p><h3 id="特殊的-m0-和-g0" tabindex="-1">特殊的 M0 和 G0 <a class="header-anchor" href="#特殊的-m0-和-g0" aria-label="Permalink to &quot;特殊的 M0 和 G0&quot;">​</a></h3><p><strong>M0</strong></p><p>M0 是启动程序后的编号为 0 的主线程，这个 M 对应的实例会在全局变量 runtime.m0 中，不需要在 heap 上分配，M0 负责执行初始化操作和启动第一个 G， 在之后 M0 就和其他的 M 一样了。</p><p><strong>G0</strong></p><p>G0 是每次启动一个 M 都会第一个创建的 gourtine，G0 仅用于负责调度的 G，G0 不指向任何可执行的函数，每个 M 都会有一个自己的 G0。在调度或系统调用时会使用 G0 的栈空间，全局变量的 G0 是 M0 的 G0。</p><h2 id="_6-gc垃圾回收机制" tabindex="-1">6.GC垃圾回收机制 <a class="header-anchor" href="#_6-gc垃圾回收机制" aria-label="Permalink to &quot;6.GC垃圾回收机制&quot;">​</a></h2><p>golang 的 GC 经历过很多次变革, 主要大更新的版本是</p><ul><li>标记清除: v1.3</li><li>三色标记: v1.5</li><li>混合写屏障+三色标记: v1.8</li></ul><h2 id="标记清除" tabindex="-1">标记清除 <a class="header-anchor" href="#标记清除" aria-label="Permalink to &quot;标记清除&quot;">​</a></h2><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ul><li>stw 暂停程序</li><li>mark: 标记可达对象(分类出可对象和不可达对象)</li><li>sweep: 清除不可达对象</li><li>stw 结束</li></ul><p>如何标记可达对象？</p><p>从程序的根节点往下面访问, 能遍历到的就是可达对象, 遍历不到的就是不可达的对象</p><h3 id="标记清除算法的优化" tabindex="-1">标记清除算法的优化？ <a class="header-anchor" href="#标记清除算法的优化" aria-label="Permalink to &quot;标记清除算法的优化？&quot;">​</a></h3><p>标记清除算法整个 GC 都是在 STW, STW 的时间过长了。<strong>为了减少 STW</strong> 的时间, golang 将 STW 的范围缩小</p><p>但是整个的 STW 还是挺长的, 特别是当需要 mark 标记的对象越多, 需要 STW 的时间越多</p><p>于是 go 1.5 就用三色标记法来动态的滚动式的做 gc 将一次长的 stw 分散到多次短暂 stw 中去</p><h2 id="三色标记" tabindex="-1">三色标记 <a class="header-anchor" href="#三色标记" aria-label="Permalink to &quot;三色标记&quot;">​</a></h2><h3 id="步骤-1" tabindex="-1">步骤 <a class="header-anchor" href="#步骤-1" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ul><li>遍历根对象的第一层可达对象标记为灰色, 不可达默认白色</li><li>将灰色对象的下一层可达对象标记为灰色, 自身标记为黑色</li><li>多次重复步骤2, 直到灰色对象为0, 只剩下白色对象和黑色对象</li><li>sweep 白色对象</li></ul><p>遍历根对象的第一层可达对象标记为灰色, 不可达默认白色。</p><p>将灰色对象 A 的下一层可达对象标记为灰色, 自身标记为黑色</p><p>继续遍历灰色对象的下层对象,重复步骤2</p><p>继续遍历灰色对象的下层对象,重复步骤2</p><p>灰色对象为0, 清理白色对象</p><h3 id="三色标记对象丢失" tabindex="-1">三色标记对象丢失 <a class="header-anchor" href="#三色标记对象丢失" aria-label="Permalink to &quot;三色标记对象丢失&quot;">​</a></h3><p>如果 gc 期间不 stw 的话有可能对象丢失</p><p><strong>一个黑色对象在 gc 期间链接了白色对象, 白色对象又没有任何的灰色对象可达就会导致对象的丢失</strong></p><p>三色标记对象丢失解决 对象丢失是在GC里面绝对不被允许的, 可以暂时存在垃圾但是不能丢失</p><p>所以还是要 STW</p><p>为了解决这个 STW 的问题, 引入了强三色不变式和弱三色不变式, 只要满足强三色不变式和弱三色不变式的任意一种就能解决 STW 的问题</p><p>强三色不变式: 一个黑色对象在 gc 期间链接了白色对象 弱三色不变式: 黑色对象链接的白色对象又没有任何的灰色对象可达 三色标记+混合写屏障就能解决这个问题</p><h3 id="三色标记-混合写屏障" tabindex="-1">三色标记 + 混合写屏障 <a class="header-anchor" href="#三色标记-混合写屏障" aria-label="Permalink to &quot;三色标记 + 混合写屏障&quot;">​</a></h3><p>步骤 STW 扫描栈, 将可达对象标记为黑色(混合写屏障也是要STW的, 网上很多文章都没说, scan stack 的时候要 STW,只是混合写屏障去掉了 rescan stack 这个步骤,时间在 1ms 左右) gc 期间 stack 创建的对象都是灰色 gc 期间在堆添加混合写屏障(链接/删除链接 元素都标记为灰色,屏障会略微减少程序性能, 因为会加一层) 示例: 解决对象丢失问题</p><p>链接对象会经过混合写屏障, 新插入的元素会标记为灰色</p><p>接下来按照三色标记继续遍历即可</p><p>Go GC 在混合写屏障之前，一直是插入写屏障，由于栈赋值没有 hook 的原 因，栈中没有启用写屏障，所以有 STW。Golang 的解决方法是：只是需要在结 束时启动 STW 来重新扫描栈。这个自然就会导致整个进程的赋值器卡顿。</p><p>Golang 没有这一步，Golang 的内存写屏障是由插入写屏障到混合写屏障过渡 的。简单介绍一下，一个对象即使被删除了最后一个指向它的指针也依旧可以 活过这一轮，在下一轮 GC 中才被清理掉。</p><ul><li>混合写屏障继承了插入写屏障的优点，起始无需 STW 打快照，直接并发扫 描垃圾即可；</li><li>混合写屏障继承了删除写屏障的优点，赋值器是黑色赋值器，GC 期间，任 何在栈上创建的新对象，均为黑色。扫描过一次就不需要扫描了，这样就 消除了插入写屏障时期最后 STW 的重新扫描栈；</li><li>混合写屏障扫描精度继承了删除写屏障，比插入写屏障更低，随着带来的 是 GC 过程全程无 STW；</li><li>混合写屏障扫描栈虽然没有 STW，但是扫描某一个具体的栈的时候，还是 要停止这个 goroutine 赋值器的工作（针对一个 goroutine 栈来说，是 暂停扫的，要么全灰，要么全黑哈，原子状态切换）。</li></ul><h4 id="gc触发时机" tabindex="-1">GC触发时机 <a class="header-anchor" href="#gc触发时机" aria-label="Permalink to &quot;GC触发时机&quot;">​</a></h4><p><strong>主动触发</strong>：调用 runtime.GC</p><p><strong>被动触发：</strong></p><p>使用系统监控，该触发条件由 <code>runtime.forcegcperiod</code> 变量控制，默认为 2 分 钟。当超过两分钟没有产生任何 GC 时，强制触发 GC。 使用步调（Pacing）算法，其核心思想是控制内存增长的比例。如 Go 的 GC 是一种比例 GC, 下一次 GC 结束时的堆大小和上一次 GC <code>存活</code>堆大小成比例.</p><h4 id="gc流程" tabindex="-1">GC流程 <a class="header-anchor" href="#gc流程" aria-label="Permalink to &quot;GC流程&quot;">​</a></h4><p>Go1.14 版本以 STW 为界限，可以将 GC 划分为五个阶段：</p><p>GCMark 标记准备阶段，为并发标记做准备工作，启动写屏障</p><p>STWGCMark 扫描标记阶段，与赋值器并发执行，写屏障开启并发</p><p>GCMarkTermination 标记终止阶段，保证一个周期内标记任务完成，停止写屏障</p><p>GCoff 内存清扫阶段，将需要回收的内存归还到堆中，写屏障关闭</p><p>GCoff 内存归还阶段，将过多的内存归还给操作系统，写屏障关闭。</p><h4 id="如何调优gc" tabindex="-1">如何调优GC <a class="header-anchor" href="#如何调优gc" aria-label="Permalink to &quot;如何调优GC&quot;">​</a></h4><p>通过 go tool pprof 和 go tool trace 等工具</p><ul><li>控制内存分配的速度，限制 Goroutine 的数量，从而提高赋值器对 CPU 的利用率。</li><li>减少并复用内存，例如使用 sync.Pool 来复用需要频繁创建临时对象，例 如提前分配足够的内存来降低多余的拷贝。</li><li>需要时，增大 GOGC 的值，降低 GC 的运行频率。</li></ul><h2 id="_7-runtime包的方法" tabindex="-1">7.runtime包的方法 <a class="header-anchor" href="#_7-runtime包的方法" aria-label="Permalink to &quot;7.runtime包的方法&quot;">​</a></h2><h2 id="_8-go的profile" tabindex="-1">8.go的profile <a class="header-anchor" href="#_8-go的profile" aria-label="Permalink to &quot;8.go的profile&quot;">​</a></h2><h2 id="_9-go实现不重启热部署" tabindex="-1">9.go实现不重启热部署？ <a class="header-anchor" href="#_9-go实现不重启热部署" aria-label="Permalink to &quot;9.go实现不重启热部署？&quot;">​</a></h2><h2 id="_10-线程和协程的区别" tabindex="-1">10.线程和协程的区别？ <a class="header-anchor" href="#_10-线程和协程的区别" aria-label="Permalink to &quot;10.线程和协程的区别？&quot;">​</a></h2><h2 id="_11-go-struct能不能比较" tabindex="-1">11.go struct能不能比较？ <a class="header-anchor" href="#_11-go-struct能不能比较" aria-label="Permalink to &quot;11.go struct能不能比较？&quot;">​</a></h2><p>某些情况可以，某些情况不可以</p><p>类型一致，只有基础类型的可以比较</p><h2 id="_12-new和make区别" tabindex="-1">12.new和make区别？ <a class="header-anchor" href="#_12-new和make区别" aria-label="Permalink to &quot;12.new和make区别？&quot;">​</a></h2><p>1.new 只分配内存,new 函数不仅仅能够为系统默认的数据类型，分配空间，自定义类型也可以使用 new 函数来分配空间,返回的永远是类型的指针，指针指向分配类型的内存地址</p><p>2.make 也是用于内存分配的，但是和 new 不同，它只用于 chan、map 以及 slice 的内存创建，而且它返回的类型就是这三个类型本身，而不是他们的指针类型，因为这三种类型就是引用类型，所以就没有必要返回他们的指针了</p><h2 id="_13-go-client如何实现长连接" tabindex="-1">13.go client如何实现长连接? <a class="header-anchor" href="#_13-go-client如何实现长连接" aria-label="Permalink to &quot;13.go client如何实现长连接?&quot;">​</a></h2><h2 id="_14-go如何避免panic" tabindex="-1">14.go如何避免panic？ <a class="header-anchor" href="#_14-go如何避免panic" aria-label="Permalink to &quot;14.go如何避免panic？&quot;">​</a></h2><h2 id="_15-go深拷贝" tabindex="-1">15.go深拷贝？ <a class="header-anchor" href="#_15-go深拷贝" aria-label="Permalink to &quot;15.go深拷贝？&quot;">​</a></h2><h2 id="_16-go-channel原理" tabindex="-1">16.go channel原理？ <a class="header-anchor" href="#_16-go-channel原理" aria-label="Permalink to &quot;16.go channel原理？&quot;">​</a></h2><h2 id="_17-defer和recover" tabindex="-1">17.defer和recover <a class="header-anchor" href="#_17-defer和recover" aria-label="Permalink to &quot;17.defer和recover&quot;">​</a></h2><h2 id="_18-gdb调试" tabindex="-1">18.GDB调试 <a class="header-anchor" href="#_18-gdb调试" aria-label="Permalink to &quot;18.GDB调试&quot;">​</a></h2><h2 id="_19-go内存分配" tabindex="-1">19.go内存分配 <a class="header-anchor" href="#_19-go内存分配" aria-label="Permalink to &quot;19.go内存分配&quot;">​</a></h2><p>内存空间包含两个重要的区域：栈（stack）和堆（heap），Go 语言的内存分配由标准库自动完成。</p><h3 id="小内存分配" tabindex="-1"><strong>小内存分配</strong> <a class="header-anchor" href="#小内存分配" aria-label="Permalink to &quot;**小内存分配**&quot;">​</a></h3><p>当变量需要小于 32 KiB 内存时，Go 语言会从名为 <code>mcache</code> 的本地缓存中为小于 32 KiB 的需求申请内存，该缓存处理内存块大小为 32 KiB 的可分配内存的链表，名为 <code>mspan</code></p><p>span 的列表按所存储 object 的大小分成至多 67 个等级，其容量从 8 字节到 32 KiB（32,768 字节），object 的数量从 1,024 至 1，而 span 的大小并非固定，是 8,192 到 32,768 字节的连续内存</p><p><strong>每种 object 大小相同 span 出现两次：其中一次包含指针的 object，另一次不包含。这种分流处理使得垃圾回收器 GC 工作更轻松，因为扫描时可以跳过不包含指针的 object。</strong></p><p>如果本地缓存上的 span 用尽，Go 语言讲会透过名为 <code>mcentral</code> 的链表来依据容量等级和是否空闲管理 span 链表</p><p><code>mcentral</code> 维护 span 为结点的双向链表，非空 span 结点包含至少一个 object 使用的链表，当 GC 扫描内存时，会清空被标记为使用完毕的 span，并将其加入非空链表中。</p><p>当本地缓存的 span 用完时，Go 语言会请求从 <code>mcentral</code> 获取一个新的 span，追加至本地链表中</p><p>再当 <code>mcentral</code> 没有可用的内存供 <code>span</code> 分配时，Go 语言再透过 OS 从 heap 中申请新的内存并加入 <code>mcentral</code> 的链表中</p><p>如果向 OS 申请的内存过多，heap 还会分配一块足够大的连续内存 arena，对于 64 位处理器的 OS 而言，起步价为 64 MB</p><p><strong>大内存分配</strong></p><p>Go 语言并非透过本地缓存来执行大于 32 KiB 的内存分配，而是将其上取至页（Page）大小并直接分配至 heap</p><h2 id="_20-进程-线程-协程区别" tabindex="-1">20.进程，线程，协程区别？ <a class="header-anchor" href="#_20-进程-线程-协程区别" aria-label="Permalink to &quot;20.进程，线程，协程区别？&quot;">​</a></h2><h3 id="进程是什么" tabindex="-1">进程是什么 <a class="header-anchor" href="#进程是什么" aria-label="Permalink to &quot;进程是什么&quot;">​</a></h3><p>进程是操作系统对一个正在运行的程序的一种抽象，进程是资源分配的最小单位。</p><h2 id="线程" tabindex="-1">线程 <a class="header-anchor" href="#线程" aria-label="Permalink to &quot;线程&quot;">​</a></h2><p><a href="https://blog.csdn.net/sinat_29846389/article/details/120558052" target="_blank" rel="noreferrer">https://blog.csdn.net/sinat_29846389/article/details/120558052</a></p><p>有了多进程，想必在操作系统上可以同时运行多个进程。那么为什么有了进程，还要线程呢？</p><p>原因如下：</p><ul><li>进程间的信息难以共享数据，父子进程并未共享内存，需要通过进程间通信（IPC），在进程间进行信息交换，性能开销较大。</li><li>创建进程（一般是调用 <code>fork</code> 方法）的性能开销较大。</li></ul><p>进程由多个线程组成 一个进程可以由多个称为线程的执行单元组成。每个线程都运行在进程的上下文中，共享着同样的代码和全局数据。</p><p>多个进程，就可以有更多的线程。多线程比多进程之间更容易共享数据，在上下文切换中线程一般比进程更高效。</p><p>原因如下：</p><p>线程之间能够非常方便、快速地共享数据。</p><p>只需将数据复制到进程中的共享区域就可以了，但需要注意避免多个线程修改同一份内存。</p><p>创建线程比创建进程要快 10 倍甚至更多。</p><p>线程都是同一个进程下自家的孩子，像是内存页、页表等就不需要了。</p><h3 id="协程是什么" tabindex="-1">协程是什么？ <a class="header-anchor" href="#协程是什么" aria-label="Permalink to &quot;协程是什么？&quot;">​</a></h3><p>协程（Coroutine）是用户态的线程。通常创建协程时，会从进程的堆中分配一段内存作为协程的栈。</p><p>线程的栈有 8 MB，而协程栈的大小通常只有 KB，而 Go 语言的协程更夸张，只有 2-4KB，非常的轻巧</p><p>也就是历史上是先有的 “协程”，再有的 “线程”，线程是在在协程的基础上添加了栈等功能后扩展出来的。</p><p>协程的优势（via InfoQ @八两）如下：</p><p>节省 CPU：避免系统内核级的线程频繁切换，造成的 CPU 资源浪费。好钢用在刀刃上。而协程是用户态的线程，用户可以自行控制协程的创建于销毁，极大程度避免了系统级线程上下文切换造成的资源浪费。</p><p>节约内存：在 64 位的Linux中，一个线程需要分配 8MB 栈内存和 64MB 堆内存，系统内存的制约导致我们无法开启更多线程实现高并发。而在协程编程模式下，可以轻松有十几万协程，这是线程无法比拟的。</p><p>稳定性：前面提到线程之间通过内存来共享数据，这也导致了一个问题，任何一个线程出错时，进程中的所有线程都会跟着一起崩溃。</p><p>开发效率：使用协程在开发程序之中，可以很方便的将一些耗时的IO操作异步化，例如写文件、耗时 IO 请求等。</p><p>协程本质上就是用户态下的线程，所以也有人说协程是 “轻线程”，但我们一定要区分用户态和内核态的区别，很关键</p><p>每个协程有自己的执行栈，可以保存自己的执行现场。 可以由用户程序按需创建协程，协程主动让出执行权时，会保存执行现场然后切换到其他协程；协程恢复执行时，会根据之前保存的执行现场，继续执行中断前的任务。 这样就实现了既轻量又灵活的由用户态进行调度的多任务模型。 因为用户程序不能操作内核空间，所以只能给协程分配用户栈，而操作系统对此一无所知，所以协程又被称为“用户态线程”</p><h2 id="_21-sync-map和map区别" tabindex="-1">21.sync.map和map区别 <a class="header-anchor" href="#_21-sync-map和map区别" aria-label="Permalink to &quot;21.sync.map和map区别&quot;">​</a></h2><h2 id="_22-go语言的调度器" tabindex="-1">22.go语言的调度器 <a class="header-anchor" href="#_22-go语言的调度器" aria-label="Permalink to &quot;22.go语言的调度器&quot;">​</a></h2><h2 id="_23-slice底层原理" tabindex="-1">23.slice底层原理 <a class="header-anchor" href="#_23-slice底层原理" aria-label="Permalink to &quot;23.slice底层原理&quot;">​</a></h2><p>1.SliceHeader三个字段，Data,Len,Cap 底层是数组</p><p>2.扩容步骤</p><p>1.预估容量扩容：</p><p>​ 1.old cap 乘以2 &lt; 所需最小容量，newCap=所需最小容量</p><p>​ 2.old cap 乘以2 &gt;= 所需最小容量, 如果len &lt;= 1024, 翻倍扩容；如果&gt;1024,扩容1.25倍循环往复</p><p>2.分配合适的内存</p><ul><li>翻新扩展：当前元素为 <code>kindNoPointers</code>，将在老 Slice cap 的地址后继续申请空间用于扩容</li><li>举家搬迁：重新申请一块内存地址，整体迁移并扩容</li></ul><p>3.如果超出old slice长度，则会生成新的slice</p><h2 id="_24-string底层原理" tabindex="-1">24.String底层原理 <a class="header-anchor" href="#_24-string底层原理" aria-label="Permalink to &quot;24.String底层原理&quot;">​</a></h2><p>1.StringHeader Data，Len(字节数目)</p><p>2.字符串不可变，底层也是共用的</p><p>3.UTF-8编码的</p><h2 id="_25-go的reflect" tabindex="-1">25.go的reflect <a class="header-anchor" href="#_25-go的reflect" aria-label="Permalink to &quot;25.go的reflect&quot;">​</a></h2><h2 id="_26-channel底层原理" tabindex="-1">26.channel底层原理 <a class="header-anchor" href="#_26-channel底层原理" aria-label="Permalink to &quot;26.channel底层原理&quot;">​</a></h2><h2 id="_27-什么是cas" tabindex="-1">27.什么是CAS？ <a class="header-anchor" href="#_27-什么是cas" aria-label="Permalink to &quot;27.什么是CAS？&quot;">​</a></h2><p>CAS 的全称为 <code>Compare And Swap</code>，直译就是比较交换。是一条 <code>CPU</code> 的原子指 令，其作用是让 CPU 先进行比较两个值是否相等，然后原子地更新某个位置的 值，其实现方式是给予硬件平台的汇编指令，在 <code>intel</code> 的 <code>CPU</code> 中，使用的 <code>cmpxchg</code> 指令，就是说 <code>CAS</code> 是靠硬件实现的，从而在硬件层面提升效率。</p><p><strong>简述过程是这样：</strong></p><p>假设包含 3 个参数内存位置(V)、预期原值(A)和新值(B)。<code>V</code> 表示要更新变量的 值，<code>E</code> 表示预期值，<code>N</code> 表示新值。仅当 <code>V</code> 值等于 <code>E</code> 值时，才会将 <code>V</code> 的值设为 <code>N</code>， 如果 <code>V</code> 值和 <code>E</code> 值不同，则说明已经有其他线程在做更新，则当前线程什么都不 做，最后 <code>CAS</code> 返回当前 <code>V</code> 的真实值。CAS 操作时抱着乐观的态度进行的，它总 是认为自己可以成功完成操作。基于这样的原理，CAS 操作即使没有锁，也可 以发现其他线程对于当前线程的干扰。</p><h2 id="_28-原子操作和锁的区别" tabindex="-1">28.原子操作和锁的区别？ <a class="header-anchor" href="#_28-原子操作和锁的区别" aria-label="Permalink to &quot;28.原子操作和锁的区别？&quot;">​</a></h2><p>原子操作由底层硬件支持，而锁则由操作系统的调度器实现。 锁应当用来保护一段逻辑，对于一个变量更新的保护。 原子操作通常执行上会更有效率，并且更能利用计算机多核的优势，如果要更 新的是一个复合对象，则应当使用 <code>atomic.Value</code> 封装好的实现。</p><h2 id="_29-协程" tabindex="-1">29.协程 <a class="header-anchor" href="#_29-协程" aria-label="Permalink to &quot;29.协程&quot;">​</a></h2><p>Golang 在语言级别支持协程，称之为 Goroutine。Golang 标准库提供的所有 系统调用操作(包括所有的同步 I/O 操作)，都会出让 CPU 给其他 Goroutine。这让 Goroutine 的切换管理不依赖于系统的线程和进程，也不依 赖于 CPU 的核心数量，而是交给 Golang 的运行时统一调度。</p><h2 id="_30-gmp" tabindex="-1">30.GMP <a class="header-anchor" href="#_30-gmp" aria-label="Permalink to &quot;30.GMP&quot;">​</a></h2><p>**G（Goroutine）：**我们所说的协程，为用户级的轻量级线程，每个 Goroutine 对象中的 sched 保存着其上下文信息。</p><p>**M（Machine）：**对内核级线程的封装，数量对应真实的 CPU 数（真正干活的对 象）。</p><p><strong>P（Processor）</strong>：即为 G 和 M 的调度对象，用来调度 G 和 M 之间的关联关系， 其数量可通过 GOMAXPROCS()来设置，默认为核心数。</p><h4 id="如何调度" tabindex="-1">如何调度？ <a class="header-anchor" href="#如何调度" aria-label="Permalink to &quot;如何调度？&quot;">​</a></h4><ul><li>每个 P 有个局部队列，局部队列保存待执行的goroutine（流程 2），当 M 绑定的 P 的的局部队列已经满了之后就会把 goroutine 放到全局队列（流 程 2-1）</li><li>每个 P 和一个 M 绑定，M 是真正的执行 P 中 goroutine 的实体（流程 3）， M 从绑定的 P 中的局部队列获取 G 来执行</li><li>当 M 绑定的 P 的局部队列为空时，M 会从全局队列获取到本地队列来执行 G （流程 3.1），当从全局队列中没有获取到可执行的 G 时候，M 会从其他 P 的局部队列中偷取 G 来执行（流程 3.2），这种从其他 P 偷的方式称为 work stealing</li><li>当 G 因系统调用（syscall）阻塞时会阻塞 M，此时 P 会和 M 解绑即 hand off，并寻找新的 idle 的 M，若没有 idle 的 M 就会新建一个 M（流程 5.1）</li><li>当 G 因 channel 或者 network I/O 阻塞时，不会阻塞 M，M 会寻找其他 runnable 的 G；当阻塞的 G 恢复后会重新进入 runnable 进入 P 队列等待执 行（流程 5.3）</li></ul><h4 id="gmp-中-work-stealing-机制" tabindex="-1">GMP 中 work stealing 机制 <a class="header-anchor" href="#gmp-中-work-stealing-机制" aria-label="Permalink to &quot;GMP 中 work stealing 机制&quot;">​</a></h4><p>获取 P 本地队列，当从绑定 P 本地 runq 上找不到可执行的 g，尝试从全局链 表中拿，再拿不到从 netpoll 和事件池里拿，最后会从别的 P 里偷任务。P 此时去唤醒一个 M。P 继续执行其它的程序。M 寻找是否有空闲的 P，如果有则 将该 G 对象移动到它本身。接下来 M 执行一个调度循环（调用 G 对象-&gt;执行-&gt; 清理线程→继续找新的 Goroutine 执行）</p><h4 id="gmp-中-hand-off-机制" tabindex="-1">GMP 中 hand off 机制 <a class="header-anchor" href="#gmp-中-hand-off-机制" aria-label="Permalink to &quot;GMP 中 hand off 机制&quot;">​</a></h4><p>当本线程 M 因为 G 进行的系统调用阻塞时，线程释放绑定的 P，把 P 转移给其 他空闲的 M 执行。 细节：当发生上线文切换时，需要对执行现场进行保护，以便下次被调度执行 时进行现场恢复。Go 调度器 M 的栈保存在 G 对象上，只需要将 M 所需要的寄存 器（SP、PC 等）保存到 G 对象上就可以实现现场保护。当这些寄存器数据被保 护起来，就随时可以做上下文切换了，在中断之前把现场保存起来。如果此时 G 任务还没有执行完，M 可以将任务重新丢到 P 的任务队列，等待下一次被调度 执行。当再次被调度执行时，M 通过访问 G 的 vdsoSP、vdsoPC 寄存器进行现场 恢复（从上次中断位置继续执行）。</p><h4 id="调度过程中的阻塞" tabindex="-1">调度过程中的阻塞 <a class="header-anchor" href="#调度过程中的阻塞" aria-label="Permalink to &quot;调度过程中的阻塞&quot;">​</a></h4><ul><li>I/O，select</li><li>block on syscall</li><li>channel</li><li>等待锁</li><li>runtime.Gosched()</li></ul><h4 id="监控线程" tabindex="-1">监控线程 <a class="header-anchor" href="#监控线程" aria-label="Permalink to &quot;监控线程&quot;">​</a></h4><p>Sysmon 也叫监控线程，变动的周期性检查，好处</p><ul><li>释放闲置超过 5 分钟的 span 物理内存；</li><li>如果超过 2 分钟没有垃圾回收，强制执行；</li><li>将长时间未处理的 netpoll 添加到全局队列；</li><li>30 向长时间运行的 G 任务发出抢占调度（超过 10ms 的 g，会进行 retake）；</li><li>收回因 syscall 长时间阻塞的 P；</li></ul><h2 id="_31-抢占式调度" tabindex="-1">31.抢占式调度 <a class="header-anchor" href="#_31-抢占式调度" aria-label="Permalink to &quot;31.抢占式调度&quot;">​</a></h2><p>在 1.14 版本之前，程序只能依靠 Goroutine 主动让出 CPU 资源才能触发调 度。这种方式存在问题有：</p><ul><li>某些 Goroutine 可以长时间占用线程，造成其它 Goroutine 的饥饿</li><li>垃圾回收需要暂停整个程序（Stop-the-world，STW），最长可能需要几分 钟的时间，导致整个程序无法工作</li></ul><p>在任何情况下，Go 运行时并行执行（注意，不是并发）的 goroutines 数量是 小于等于 P 的数量的。为了提高系统的性能，P 的数量肯定不是越小越好，所 以官方默认值就是 CPU 的核心数，设置的过小的话，如果一个持有 P 的 M， 由于 P 当前执行的 G 调用了 syscall 而导致 M 被阻塞，那么此时关键点： GO 的调度器是迟钝的，它很可能什么都没做，直到 M 阻塞了相当长时间以 后，才会发现有一个 P/M 被 syscall 阻塞了。然后，才会用空闲的 M 来强这 个 P。**通过 sysmon 监控实现的抢占式调度，**最快在 20us，最慢在 10-20ms 才 会发现有一个 M 持有 P 并阻塞了。操作系统在 1ms 内可以完成很多次线程调 度（一般情况 1ms 可以完成几十次线程调度），Go 发起 IO/syscall 的时候执 行该 G 的 M 会阻塞然后被 OS 调度走，P 什么也不干，sysmon 最慢要 10-20ms 才能发现这个阻塞，说不定那时候阻塞已经结束了，这样宝贵的 P 资源就这么 被阻塞的 M 浪费了。</p><h2 id="_32-defer原理" tabindex="-1">32.defer原理 <a class="header-anchor" href="#_32-defer原理" aria-label="Permalink to &quot;32.defer原理&quot;">​</a></h2><h2 id="_33-错误处理" tabindex="-1">33.错误处理 <a class="header-anchor" href="#_33-错误处理" aria-label="Permalink to &quot;33.错误处理&quot;">​</a></h2><h2 id="_34-grpc为什么快" tabindex="-1">34.GRPC为什么快？ <a class="header-anchor" href="#_34-grpc为什么快" aria-label="Permalink to &quot;34.GRPC为什么快？&quot;">​</a></h2><p><a href="https://blog.csdn.net/weixin_40580582/article/details/118661409" target="_blank" rel="noreferrer">https://blog.csdn.net/weixin_40580582/article/details/118661409</a></p><p>1.基于HTTP/2 多路复用</p><p>2.基于protobuf协议，高效，编码解码高效，头部压缩，二进制分帧，支持服务器主动推送资源</p><p>3.流式处理，支持客户端流式，服务端流式，双向流式</p>`,249),s=[t];function i(r,p,c,d,h,u){return n(),e("div",null,s)}const g=a(o,[["render",i]]);export{m as __pageData,g as default};
